    /**
     * Reads input stream with a size limit to prevent memory exhaustion attacks.
     */
    static byte[] readWithSizeLimit(InputStream inputStream, int maxSize) throws IOException, PayloadTooLargeException {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        byte[] chunk = new byte[8192];
        int totalRead = 0;
        int bytesRead;

        while ((bytesRead = inputStream.read(chunk)) != -1) {
            totalRead += bytesRead;
            if (totalRead > maxSize) {
                throw new PayloadTooLargeException("Payload exceeds maximum size of " + maxSize + " bytes.");
            }
            buffer.write(chunk, 0, bytesRead);
        }

        return buffer.toByteArray();
    }

